easy.solution:
def first_negative(nums):
    for n in nums:
        if n < 0:
            return n
    return None

medium.solution:
def sum_pos_evens(nums):
    total = 0
    for n in nums:
        if n <= 0 or n % 2 != 0:
            continue
        total += n
    return total

hard.solution:
def first_uniq_char(s):
    counts = {}
    for c in s:
        counts[c] = counts.get(c, 0) + 1
    for idx, c in enumerate(s):
        if counts[c] == 1:
            return idx
    return -1

